@@ -0,0 +1,103 @@
+    1: using Microsoft.Extensions.Options;
+    2: 
+    3: namespace ReviewBot.Api.Tracing;
+    4: 
+    5: public sealed class TraceCleanupService(
+    6:     IOptions<TracingOptions> options,
+    7:     TimeProvider clock,
+    8:     ILogger<TraceCleanupService> logger) : BackgroundService
+    9: {
+   10:     private readonly TracingOptions options = options?.Value ?? throw new ArgumentNullException(nameof(options));
+   11: 
+   12:     protected override async Task ExecuteAsync(CancellationToken stoppingToken)
+   13:     {
+   14:         try
+   15:         {
+   16:             while (true)
+   17:             {
+   18:                 await Task.Delay(TimeSpan.FromHours(24), clock, stoppingToken).ConfigureAwait(false);
+   19:                 if (!options.Enabled)
+   20:                 {
+   21:                     continue;
+   22:                 }
+   23: 
+   24:                 try
+   25:                 {
+   26:                     RunCleanup();
+   27:                 }
+   28:                 catch (Exception ex) when (ex is not OperationCanceledException)
+   29:                 {
+   30:                     logger.LogError(ex, "Trace cleanup failed; will retry next interval");
+   31:                 }
+   32:             }
+   33:         }
+   34:         catch (OperationCanceledException) when (stoppingToken.IsCancellationRequested)
+   35:         {
+   36:             logger.LogInformation("Trace cleanup service stopped");
+   37:         }
+   38:     }
+   39: 
+   40:     internal void RunCleanup()
+   41:     {
+   42:         var tracesDir = options.TracesDir;
+   43:         if (!Directory.Exists(tracesDir))
+   44:         {
+   45:             return;
+   46:         }
+   47: 
+   48:         var cutoff = clock.GetUtcNow().UtcDateTime - TimeSpan.FromDays(options.RetentionDays);
+   49:         var deletedByAge = 0;
+   50:         var remainingFiles = new List<FileInfo>();
+   51: 
+   52:         foreach (var fi in Directory
+   53:             .EnumerateFiles(tracesDir, "*.json", SearchOption.AllDirectories)
+   54:             .Select(path => new FileInfo(path)))
+   55:         {
+   56:             if (fi.LastWriteTimeUtc < cutoff)
+   57:             {
+   58:                 TryDelete(fi.FullName);
+   59:                 deletedByAge++;
+   60:             }
+   61:             else
+   62:             {
+   63:                 remainingFiles.Add(fi);
+   64:             }
+   65:         }
+   66: 
+   67:         var maxBytes = (long)options.MaxDiskMb * 1024 * 1024;
+   68:         var totalBytes = remainingFiles.Sum(fi => fi.Length);
+   69:         var deletedBySize = 0;
+   70: 
+   71:         foreach (var fi in remainingFiles.OrderBy(fi => fi.LastWriteTimeUtc))
+   72:         {
+   73:             if (totalBytes <= maxBytes)
+   74:             {
+   75:                 break;
+   76:             }
+   77: 
+   78:             TryDelete(fi.FullName);
+   79:             totalBytes -= fi.Length;
+   80:             deletedBySize++;
+   81:         }
+   82: 
+   83:         if (deletedByAge > 0 || deletedBySize > 0)
+   84:         {
+   85:             logger.LogInformation(
+   86:                 "Trace cleanup: deleted {ByAge} expired file(s) and {BySize} file(s) for disk cap",
+   87:                 deletedByAge,
+   88:                 deletedBySize);
+   89:         }
+   90:     }
+   91: 
+   92:     private void TryDelete(string path)
+   93:     {
+   94:         try
+   95:         {
+   96:             File.Delete(path);
+   97:         }
+   98:         catch (Exception ex) when (ex is not OperationCanceledException)
+   99:         {
+  100:             logger.LogWarning(ex, "Failed to delete trace file {Path}", path);
+  101:         }
+  102:     }
+  103: }
